import{initializeApp}from"https://www.gstatic.com/firebasejs/12.10.0/firebase-app.js";import{getFirestore,collection,addDoc,getDocs,doc,setDoc,updateDoc,deleteDoc}from"https://www.gstatic.com/firebasejs/12.10.0/firebase-firestore.js";export class Firebase{constructor(t){this.app=initializeApp(t),this.db=getFirestore(this.app)}async add(t,e){return await addDoc(collection(this.db,t),e)}async getAll(t){const e=await getDocs(collection(this.db,t)),s=[];return e.forEach(t=>{s.push({id:t.id,...t.data()})}),s}async set(t,e,s){return await setDoc(doc(this.db,t,e),s)}async update(t,e,s){return await updateDoc(doc(this.db,t,e),s)}async delete(t,e){return await deleteDoc(doc(this.db,t,e))}}